(() => {
  'use strict';
  if (window.__pcbw_imgDirectorInit) return;
  window.__pcbw_imgDirectorInit = true;

  const NS = '__pcbw_imgDirector';

  const STYLE_PRESETS = {
    cinematic: {
      prefix: 'cinematic photography, dramatic lighting, film grain, shallow depth of field, ',
      suffix: ', 8k uhd, award-winning photography, (negativePrompt:::cartoon, anime, drawing, painting, low quality)'
    },
    anime: {
      prefix: 'anime illustration, vibrant colors, clean lineart, ',
      suffix: ', high quality anime art, detailed, studio quality, (negativePrompt:::photorealistic, 3d render, low quality, blurry)'
    },
    oil_painting: {
      prefix: 'oil painting, classical art style, rich brushwork, ',
      suffix: ', masterwork painting, museum quality, textured canvas, (negativePrompt:::photograph, digital art, low quality)'
    },
    concept_art: {
      prefix: 'concept art, digital painting, professional illustration, ',
      suffix: ', trending on artstation, highly detailed, professional quality, (negativePrompt:::photograph, low quality, amateur)'
    },
    watercolor: {
      prefix: 'watercolor painting, soft washes, delicate brushstrokes, ',
      suffix: ', fine art watercolor, elegant, atmospheric, (negativePrompt:::digital art, photograph, harsh lines, low quality)'
    },
    pixel_art: {
      prefix: 'pixel art, retro game style, limited palette, ',
      suffix: ', clean pixels, crisp edges, nostalgic, (negativePrompt:::photorealistic, blurry, 3d render)'
    }
  };

  function ensureState() {
    if (!oc.thread.customData) oc.thread.customData = {};
    if (!oc.thread.customData[NS]) {
      oc.thread.customData[NS] = {
        activeStyle: 'cinematic',
        promptHistory: [],
        aspectPreference: 'square',
        negativeDefaults: 'low quality, blurry, distorted',
        sessionPromptCount: 0
      };
    }
    return oc.thread.customData[NS];
  }

  function applyStyleToCharacter(state) {
    var preset = STYLE_PRESETS[state.activeStyle];
    if (!preset || !oc.character) return;
    oc.character.imagePromptPrefix = preset.prefix;
    oc.character.imagePromptSuffix = preset.suffix;
  }

  function processCommand(text) {
    var state = ensureState();
    var lower = (text || '').toLowerCase().trim();

    if (lower.startsWith('/style ')) {
      var styleName = lower.substring(7).trim().replace(/\s+/g, '_');
      if (STYLE_PRESETS[styleName]) {
        state.activeStyle = styleName;
        applyStyleToCharacter(state);
      }
    } else if (lower === '/styles') {
      // Let the AI list the styles
    } else if (lower.startsWith('/aspect ')) {
      var aspect = lower.substring(8).trim();
      if (['square', 'portrait', 'landscape', 'wide'].includes(aspect)) {
        state.aspectPreference = aspect;
      }
    } else if (lower.startsWith('/negative ')) {
      state.negativeDefaults = text.trim().substring(10).trim();
    } else if (lower === '/history') {
      // Let AI handle via state context
    }
  }

  oc.thread.on('MessageAdded', function() {
    try {
      var state = ensureState();
      var msgs = oc.thread.messages;
      if (!msgs || msgs.length === 0) return;
      var last = msgs[msgs.length - 1];
      if (last.author !== 'user') return;

      state.sessionPromptCount++;
      var text = (last.content || '').trim();

      if (text.startsWith('/')) {
        processCommand(text);
      } else if (text.length > 5) {
        state.promptHistory.push({
          input: text.substring(0, 200),
          style: state.activeStyle,
          at: Date.now()
        });
        if (state.promptHistory.length > 30) {
          state.promptHistory = state.promptHistory.slice(-30);
        }
      }

      applyStyleToCharacter(state);

      var contextHint = '[Active style: ' + state.activeStyle + ', Aspect: ' + state.aspectPreference + ', Prompts crafted: ' + state.sessionPromptCount + ']';
      if (oc.character && oc.character.reminderMessage !== undefined) {
        var baseReminder = 'You are an expert art director and image prompt engineer. When the user describes a scene or concept, craft a detailed, optimized image generation prompt. Structure prompts with: subject, composition, lighting, mood, style details, and quality tags. Always consider the active style preset. Explain your prompt choices briefly after providing the prompt. Format the crafted prompt in a code block for easy copying.';
        oc.character.reminderMessage = baseReminder + '\n' + contextHint;
      }
    } catch (e) {
      console.warn('[ImageDirectorBot] MessageAdded handler error:', e);
    }
  });

  var state = ensureState();
  applyStyleToCharacter(state);
})();
